    /** TextRank extractive summary over a multi-paragraph plain text document. Pure-Rust, deterministic, no external services required. */
    public function test_summarization_extractive_smoke(): void
    {
        $inputMockBaseUrl = getenv('MOCK_SERVER_SUMMARIZATION_EXTRACTIVE_SMOKE')
        ?: getenv('MOCK_SERVER_URL') . '/fixtures/summarization_extractive_smoke';
        $inputJson = str_replace("\$mock_url", $inputMockBaseUrl, json_encode([
            'kind' => 'uri',
            'uri' => "\$mock_url/text/book_war_and_peace_1p.txt",
        ]));
        $input = \Xberg\ExtractInput::from_json($inputJson);
        $config = \Xberg\ExtractionConfig::from_json(json_encode(['summarization' => [
            'strategy' => 'extractive',
            'maxTokens' => 80,
        ]]));
        $result = Xberg::extract($input, $config);

